        this.title = b.title;
        this.detail = b.detail;
        this.wikiUrl = b.wikiUrl;
        this.skill = b.skill;
        this.fromLevel = b.fromLevel;
        this.toLevel = b.toLevel;
        this.xp = b.xp;
    }

