        return fromLevel;
    }

    public int getToLevel()
    {
        return toLevel;
    }

    public String getReason()
    {
        return reason;
    }
}

package com.ironpath.overlay;

import com.ironpath.IronmanPathConfig;
import com.ironpath.model.InfoPlanStep;
