        stringValue = str;
    }

    @Override
    public String toString()
    {
        return stringValue;
    }

    @Override
    public boolean evaluate(SimpleTOBData data)
    {
        int checkValue = data.getValue(split);
        return FilterUtil.compare(compare, time, checkValue);
