                            dataManager.increment(DataPoint.SOTE_SPECS_P3);
                            dataManager.increment(DataPoint.SOTE_SPECS_TOTAL);
                        }
                        break;
                    case LEFT_TOB:
                        if (dataManager.get(DataPoint.SOTE_TOTAL_TIME) != 0)
                        {
