            if (d.soteStartAccurate && d.soteEndAccurate)
            {
                soteCount++;
            }
            if (d.xarpStartAccurate && d.xarpEndAccurate)
            {
                xarpCount++;
            }
            if (d.verzikStartAccurate && d.verzikEndAccurate)
            {
                verzikCount++;
            }
